package hw05.model.interactStrategies;

import java.awt.Point;
import java.awt.geom.Point2D;

import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author cindy
 * Elastic Collision without decomposition
 *
 */
public class CollideStrategy implements  IInteractStrategy {

	@Override
	public IBallCmd interactWith(IBall source, IBall target, IDispatcher<IBallCmd> disp) {
		Point lSource = source.getLocation();
		Point lTarget = target.getLocation();

		double dx = lTarget.x - lSource.x;
		double dy = lTarget.y - lSource.y;
		double distance = Math.sqrt(dx * dx + dy * dy);

		double minSeparation = source.getRadius() + target.getRadius();

		if (distance < minSeparation && distance > 0) {
			double mSource = source.getRadius() * source.getRadius();
			double mTarget = target.getRadius() * target.getRadius();
			double redMass = reducedMass(mSource, mTarget);

			Point2D.Double normalVec = calcUnitVec(lSource, lTarget, distance);

			Point2D.Double imp = impulse(normalVec, source.getVelocity(), target.getVelocity(), redMass);

			// source gets negative impulse, target gets positive impulse
			Point2D.Double negImp = new Point2D.Double(-imp.x, -imp.y);
			updateVelocity(source, mSource, negImp);
			updateVelocity(target, mTarget, imp);

			// Nudge source away from target
			Point nudge = calcNudgeVec(normalVec, minSeparation, distance);
			source.setLocation(new Point(lSource.x - nudge.x, lSource.y - nudge.y));
		}

		return (context, d) -> {};
	}

	/**
	 * Returns the reduced mass of the two balls (m1*m2)/(m1+m2)
	 */
	protected double reducedMass(double mSource, double mTarget) {
		if (Double.isInfinite(mSource)) return mTarget;
		if (Double.isInfinite(mTarget)) return mSource;
		return (mSource * mTarget) / (mSource + mTarget);
	}

	/**
	 * Calculate the unit vector from source to target.
	 */
	Point2D.Double calcUnitVec(Point lSource, Point lTarget, double distance) {
		double dx = lTarget.x - lSource.x;
		double dy = lTarget.y - lSource.y;
		return new Point2D.Double(dx / distance, dy / distance);
	}

	/**
	 * Calculates the impulse of the collision in the direction from source to target.
	 */
	protected Point2D.Double impulse(Point2D.Double normalVec, Point vSource, Point vTarget, double reducedMass) {
		// Relative velocity of source with respect to target
		double dvx = vSource.x - vTarget.x;
		double dvy = vSource.y - vTarget.y;
		// Dot product of relative velocity with normal
		double dot = dvx * normalVec.x + dvy * normalVec.y;
		// Impulse magnitude (factor of 2 for elastic collision)
		double impMag = 2.0 * reducedMass * dot;
		return new Point2D.Double(impMag * normalVec.x, impMag * normalVec.y);
	}


	/**
	 * The multiplicative factor to increase the separation distance
	 */
	private static final double NudgeFactor = 1.1;

	/**
	 * Calculate the nudge vector to push source away from target.
	 */
	Point calcNudgeVec(Point2D.Double normalVec, double minSeparation, double distance) {
		double nudgeDist = (minSeparation * NudgeFactor - distance) / 2.0;
		int nx = (int) Math.round(nudgeDist * normalVec.x);
		int ny = (int) Math.round(nudgeDist * normalVec.y);
		return new Point(nx, ny);
	}

	/**
	 * Updates velocity of a ball given an impulse vector.
	 */
	protected void updateVelocity(IBall aBall, double mass, Point2D.Double impulseVec) {
		Point v = aBall.getVelocity();
		int newVx = (int) Math.round(v.x + impulseVec.x / mass);
		int newVy = (int) Math.round(v.y + impulseVec.y / mass);
		aBall.setVelocity(new Point(newVx, newVy));
	}

	@Override
	public void init(IBall context) {
		// no init needed
	}

}

