/**
 * The Criteria strategy that is satisfied when the two balls collide
 * @author cindy
 *
 */
public class CollideCriteriaStrategy implements IUpdateStrategy{

	@Override
	public void updateState(final IBall source, IDispatcher<IBallCmd> dispatcher) {
		dispatcher.updateAll((observedBall, disp) -> {
			if (observedBall != source) {
				Point ls = source.getLocation();
				Point lt = observedBall.getLocation();
				double dx = lt.x - ls.x;
				double dy = lt.y - ls.y;
				double dist = Math.sqrt(dx * dx + dy * dy);
				double minSep = source.getRadius() + observedBall.getRadius();
				if (dist < minSep) {
					IBallCmd cmd = source.interactWithThen(observedBall, disp);
					cmd.apply(source, disp);
				}
			}
		});
	}

	@Override
	public void init(IBall context) {
		// no init needed
	}

}

