package visitorDemoExercises.listFWVisitorExercises.model.visitors;

import provided.listFW.IList;
import provided.listFW.IListAlgo;
import provided.listFW.MTList;
import provided.listFW.NEList;

/**
 * Return a list with the smallest element from the list removed.
 * Do this with a single pass through the the list!
 * The input parameter is not used ("nu").
 * @author Son Nguyen and Charlie Lockyer
 */
public class RemoveSmallestRevAlgo implements IListAlgo {
	private static class MinListState {
		private final int min;
		private final IList listWithMinRemoved;
		private final IList originalList;

		private MinListState(int min, IList listWithMinRemoved, IList originalList) {
			this.min = min;
			this.listWithMinRemoved = listWithMinRemoved;
			this.originalList = originalList;
		}
	}

	private final IListAlgo helper = new IListAlgo() {
		@Override
		public Object emptyCase(MTList host, Object... nu) {
			return new MinListState(Integer.MAX_VALUE, MTList.Singleton, MTList.Singleton);
		}

		@Override
		public Object nonEmptyCase(NEList host, Object... nu) {
			MinListState restState = (MinListState) host.getRest().execute(this);
			int first = (Integer) host.getFirst();
			IList rebuiltOriginal = new NEList(first, restState.originalList);

			if (first <= restState.min) {
				return new MinListState(first, restState.originalList, rebuiltOriginal);
			}
			return new MinListState(restState.min, new NEList(first, restState.listWithMinRemoved), rebuiltOriginal);
		}
	};
	/**
	 * Returns Min_value always.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return MTList.Singleton;
	}

	/**
	 * Returns the list depending if the condition has been met.
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		return ((MinListState) host.execute(helper)).listWithMinRemoved;
	}

}

